# %% ../../nbs/features/13_fsd.ipynb #3253d621
class FSDEvaluator(FeatureEvaluator):
    """Extracts normalized densities for all fragment size buckets."""

    name = "FsdOnTarget"
    source_file = ".FSD.ontarget.parquet"
    tier = 1
    category = "fragmentation"

    def extract(self, df: pd.DataFrame) -> dict[str, float]:
        extracted = {}
        try:
            if df.empty:
                return extracted

            cols = set(df.columns)

            if "total" not in cols:
                log.warning("fsd_ontarget_missing_total_col")
                return extracted

            # FSD has multiple rows for groups (e.g. per-chromosome or total), we will just aggregate globally first
            total_reads = df["total"].sum()
            if total_reads == 0:
                return extracted

            for c in df.columns:
                if c not in ["region", "total", "chrom"]:
                    bucket_sum = df[c].sum()
                    extracted[f"fsd_ontarget_density_{c}"] = float(
                        bucket_sum / total_reads
                    )

            # Special 143/166 proxy
            # 143 falls in "140-144", 166 falls in "165-169"
            if "140-144" in cols and "165-169" in cols:
                v143 = df["140-144"].sum()
                v166 = df["165-169"].sum()
                if v166 > 0:
                    extracted["fsd_ontarget_143_166_ratio"] = float(v143 / v166)

            return extracted
        except Exception as e:
            log.exception("extraction_failed", evaluator=self.name, error=str(e))
            return {}
